// Main JS for Student Dashboard

$(document).ready(function () {
  // Sidebar toggle
  $("#sidebarToggle, #sidebarToggleTop").on("click", function (e) {
    e.preventDefault();
    $("body").toggleClass("sidebar-toggled");
    $(".sidebar").toggleClass("toggled");
    if ($(".sidebar").hasClass("toggled")) {
      $('.sidebar').addClass('show');
      localStorage.setItem('sb|sidebar', JSON.stringify({ state: 'hidden' }));
    } else {
      $('.sidebar').removeClass('show');
      localStorage.setItem('sb|sidebar', JSON.stringify({ state: 'shown' }));
    }
  });

  // Prevent the content wrapper from scrolling when the fixed sidebar is being scrolled
  $(document).on("mousewheel DOMMouseScroll wheel", ".sidebar", function (e) {
    if ($window.width() < 768) {
      e.preventDefault();
    }
  });

  // Smooth scroll behavior
  $('a[href^="#"]').on('click', function (e) {
    e.preventDefault();
    var target = $(this.getAttribute('href'));
    if (target.length) {
      $('html, body').stop().animate({
        scrollTop: target.offset().top
      }, 1000);
    }
  });

  // DataTable initialization
  if ($.fn.DataTable) {
    var table = $('#attendanceTable').DataTable({
      "pageLength": 10,
      "ordering": true,
      "searching": true,
      "info": true,
      "lengthChange": true
    });
  }

  // Form validation
  var forms = document.querySelectorAll('.needs-validation');
  Array.prototype.slice.call(forms).forEach(function (form) {
    form.addEventListener('submit', function (event) {
      if (!form.checkValidity()) {
        event.preventDefault();
        event.stopPropagation();
      }
      form.classList.add('was-validated');
    }, false);
  });

  // Initialize tooltips
  if (typeof $.fn.tooltip === 'function') {
    $('[data-toggle="tooltip"]').tooltip();
  }

  // Initialize popovers
  if (typeof $.fn.popover === 'function') {
    $('[data-toggle="popover"]').popover();
  }
});

// Logout functionality
function confirmLogout() {
  if (confirm('Are you sure you want to logout?')) {
    window.location.href = 'logout.php';
  }
}
